import React from 'react';

const ResultPreview = ({ 
  originalImage, 
  compressedImage, 
  originalSize, 
  compressedSize, 
  fileName, 
  setFileName, 
  onDownload, 
  onReset 
}) => {
  const formatFileSize = (bytes) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const calculateCompressionPercentage = () => {
    if (originalSize === 0) return 0;
    return ((originalSize - compressedSize) / originalSize * 100).toFixed(1);
  };

  const getFileExtension = () => {
    if (!originalImage) return '';
    // Default to jpg for compressed images
    return '.jpg';
  };

  const handleFileNameChange = (e) => {
    // Remove file extension if user tries to add it
    let name = e.target.value;
    name = name.replace(/\.(jpg|jpeg|png)$/i, '');
    setFileName(name);
  };

  return (
    <div className="space-y-6">
      <div className="grid md:grid-cols-2 gap-6">
        <div className="space-y-3">
          <h3 className="font-semibold text-gray-700">Original Image</h3>
          <div className="relative group">
            <img
              src={originalImage}
              alt="Original"
              className="w-full h-48 object-contain bg-gray-50 rounded-lg border border-gray-200"
            />
            <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
              {formatFileSize(originalSize)}
            </div>
          </div>
        </div>

        {compressedImage && (
          <div className="space-y-3">
            <h3 className="font-semibold text-gray-700">Compressed Image</h3>
            <div className="relative group">
              <img
                src={compressedImage}
                alt="Compressed"
                className="w-full h-48 object-contain bg-gray-50 rounded-lg border border-gray-200"
              />
              <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
                {formatFileSize(compressedSize)}
              </div>
            </div>
          </div>
        )}
      </div>

      {compressedImage && (
        <>
          <div className="bg-green-50 border border-green-200 rounded-lg p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-green-800 font-medium">Compression Successful!</p>
                <p className="text-green-600 text-sm mt-1">
                  Reduced size by {calculateCompressionPercentage()}%
                </p>
              </div>
              <div className="text-right">
                <p className="text-2xl font-bold text-green-700">{calculateCompressionPercentage()}%</p>
                <p className="text-xs text-green-600">size reduction</p>
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                File Name (without extension)
              </label>
              <div className="flex gap-2">
                <input
                  type="text"
                  value={fileName}
                  onChange={handleFileNameChange}
                  placeholder="Enter file name"
                  className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent"
                />
                <span className="flex items-center px-3 py-2 bg-gray-100 border border-gray-300 rounded-lg text-gray-600">
                  {getFileExtension()}
                </span>
              </div>
              <p className="text-xs text-gray-500 mt-1">
                File will be saved as: {fileName}{getFileExtension()}
              </p>
            </div>

            <div className="flex flex-wrap gap-3">
              <button
                onClick={onDownload}
                className="btn-primary"
              >
                Download Compressed Image
              </button>

              <button
                onClick={onReset}
                className="btn-secondary"
              >
                Upload New Image
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export default ResultPreview;
